private void updateMaxScores(int target) throws IOException {
    if (head.size() == 0) {
      upTo = tail[0].scorer.advanceShallow(target);
    } else {
      int newUpTo = DocIdSetIterator.NO_MORE_DOCS;
      for (DisiWrapper w : head) {
        if (w.doc <= newUpTo) {
